  BEGIN ORDS.DELETE_HANDLER('lubrimec', 'precios-ventas/:id', 'PUT');    EXCEPTION WHEN OTHERS THEN NULL; END;
  BEGIN ORDS.DELETE_HANDLER('lubrimec', 'precios-ventas/:id', 'DELETE'); EXCEPTION WHEN OTHERS THEN NULL; END;

